"""Penalty method with L-BFGS-B for circle packing optimization"""
import numpy as np
from scipy.optimize import minimize

def construct_packing():
    """Use penalty method with L-BFGS-B: soft constraints via penalty functions."""
    n = 26

    def get_initial_positions(seed=42):
        np.random.seed(seed)
        centers = np.zeros((n, 2))
        r = 0.095
        row_counts = [5, 4, 5, 4, 5, 3]
        y_spacing = r * np.sqrt(3)
        idx = 0
        for row, count in enumerate(row_counts):
            y = r + row * y_spacing
            x_positions = [r + i * 2 * r for i in range(count)] if count != 4 else [2 * r + i * 2 * r for i in range(4)]
            for x in x_positions:
                centers[idx] = [x, y]
                idx += 1
        if seed != 42:
            centers += np.random.uniform(-0.02, 0.02, centers.shape)
            centers = np.clip(centers, 0.05, 0.95)
        return centers

    def pack_vars(centers, radii):
        x = np.zeros(3 * n)
        for i in range(n):
            x[3*i], x[3*i+1], x[3*i+2] = centers[i, 0], centers[i, 1], radii[i]
        return x

    def unpack_vars(x):
        return np.hstack([x[0::3].reshape(n, 1), x[1::3].reshape(n, 1)]), x[2::3].copy()

    def penalty_objective(x, pw):
        """Objective: -sum(r) + pw * (boundary_penalty + overlap_penalty)."""
        centers, radii = unpack_vars(x)
        obj = -np.sum(radii)

        boundary_pen = 0.0
        for i in range(n):
            xi, yi, ri = centers[i, 0], centers[i, 1], radii[i]
            boundary_pen += max(0, ri - xi)**2 + max(0, ri - yi)**2
            boundary_pen += max(0, xi + ri - 1)**2 + max(0, yi + ri - 1)**2

        overlap_pen = 0.0
        for i in range(n):
            for j in range(i+1, n):
                dist = np.linalg.norm(centers[i] - centers[j])
                overlap_pen += max(0, radii[i] + radii[j] - dist)**2

        return obj + pw * (boundary_pen + overlap_pen)

    def penalty_gradient(x, pw):
        """Gradient of penalty objective."""
        centers, radii = unpack_vars(x)
        grad = np.zeros_like(x)
        grad[2::3] = -1.0

        for i in range(n):
            xi, yi, ri = centers[i, 0], centers[i, 1], radii[i]
            if ri > xi:
                grad[3*i+2] += pw * 2 * (ri - xi)
                grad[3*i] -= pw * 2 * (ri - xi)
            if ri > yi:
                grad[3*i+2] += pw * 2 * (ri - yi)
                grad[3*i+1] -= pw * 2 * (ri - yi)
            if xi + ri > 1:
                grad[3*i+2] += pw * 2 * (xi + ri - 1)
                grad[3*i] += pw * 2 * (xi + ri - 1)
            if yi + ri > 1:
                grad[3*i+2] += pw * 2 * (yi + ri - 1)
                grad[3*i+1] += pw * 2 * (yi + ri - 1)

        for i in range(n):
            for j in range(i+1, n):
                dx, dy = centers[i,0] - centers[j,0], centers[i,1] - centers[j,1]
                dist = np.sqrt(dx*dx + dy*dy)
                viol = radii[i] + radii[j] - dist
                if viol > 0 and dist > 1e-10:
                    grad[3*i] -= pw * 2 * viol * (dx/dist)
                    grad[3*i+1] -= pw * 2 * viol * (dy/dist)
                    grad[3*j] += pw * 2 * viol * (dx/dist)
                    grad[3*j+1] += pw * 2 * viol * (dy/dist)
                    grad[3*i+2] += pw * 2 * viol
                    grad[3*j+2] += pw * 2 * viol
        return grad

    def compute_max_radii(centers):
        """Expand radii to maximum valid values given positions."""
        radii = np.array([min(x, y, 1-x, 1-y) for x, y in centers])
        for _ in range(100):
            expanded = False
            for i in range(n):
                max_r = min(centers[i,0], centers[i,1], 1-centers[i,0], 1-centers[i,1])
                for j in range(n):
                    if i != j:
                        max_r = min(max_r, np.linalg.norm(centers[i] - centers[j]) - radii[j])
                if max_r > radii[i] + 1e-10:
                    radii[i] = max_r
                    expanded = True
            if not expanded:
                break
        return radii

    bounds = [(0.001, 0.999), (0.001, 0.999), (0.001, 0.5)] * n
    best_sum, best_solution = 0, None

    for pw in [500, 1000, 2000]:
        for restart in range(3):
            seed = 42 + restart * 17 + int(pw)
            centers_init = get_initial_positions(seed)
            radii_init = np.maximum(np.array([min(x, y, 1-x, 1-y) for x, y in centers_init]), 0.01)
            x0 = pack_vars(centers_init, radii_init)

            result = minimize(lambda x: penalty_objective(x, pw), x0, method='L-BFGS-B',
                            jac=lambda x: penalty_gradient(x, pw), bounds=bounds,
                            options={'maxiter': 1500, 'ftol': 1e-9})

            centers, _ = unpack_vars(result.x)
            radii = compute_max_radii(centers)
            current_sum = np.sum(radii)

            if current_sum > best_sum:
                best_sum = current_sum
                best_solution = (centers.copy(), radii.copy())

    return best_solution[0], best_solution[1], np.sum(best_solution[1])
